FROM jsonb_array_elements('[{"id":"firsdown-sp5","name":"Firsdown","village":"Firsdown","town":"Salisbury","county":"Wiltshire","postcode":"SP5","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":50.99692,"lng":-1.86588},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"flexcombe-gu32","name":"Flexcombe","village":"Flexcombe","town":"Petersfield","county":"Hampshire","postcode":"GU32","hubCity":"Guildford","regionDir":"","settlementType":"","subRegion":"Petersfield","coords":{"lat":51.0228,"lng":-0.9456},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"flexcombe-gu33","name":"Flexcombe","village":"","town":"Liss","county":"Hampshire","postcode":"GU33","hubCity":"","regionDir":"","settlementType":"","subRegion":"","coords":{"lat":51.0228,"lng":-0.9456},"coordsSource":"unset","houseTypeIds":[],"status":"researched","overview":"A two-house place (Wikipedia''s description) in the civil parish of Liss, East Hampshire district. The settlement is effectively Flexcombe Farm and a small courtyard of barn conversions at Flexcombe Farm Cottages, off Flexcombe Lane between Liss and Stodham. It sits inside the South Downs National Park, immediately west of the A3 bypass and a few miles north of Petersfield. The seed CSV records the postcode as GU32; Wikipedia, Royal Mail and Liss-area address listings confirm the post town is LISS and the postcode district is GU33 — the GU32 entry in the seed is an error, corrected here. Day-to-day services are at Liss (~2 mi south-east) for primary school, station, shops and pubs, and Petersfield for the wider shopping and rail offer.","character":"Single-courtyard rural settlement of converted farm buildings in a working-farm setting, surrounded by chalk-clay countryside and the SDNP''s hangers landscape. Effectively a private courtyard rather than a village — no shared public realm beyond the farm track.","amenities":["Flexcombe Farm Cottages (courtyard of barn conversions)","Flexcombe Lane footpath access onto the South Downs","(at Liss ~2 mi:) Liss Forest village shop and post office","Liss Triangle shops and cafés","Liss Sports Pavilion","Riverside walks along Caker Stream"],"schools":[{"name":"Liss Infant School","phase":"Primary (infant)","ofsted":"Good","distance":"0.9 mi","url":"https://www.lissinfant.hants.sch.uk/"},{"name":"Liss Junior School","phase":"Primary (junior)","ofsted":"Good","distance":"2.0 mi","url":"https://www.lissjunior.hants.sch.uk/"},{"name":"Churcher''s College","phase":"Independent (3–18)","ofsted":null,"distance":"2.1 mi","url":"https://www.churcherscollege.com/"},{"name":"Bohunt School (Liphook)","phase":"Secondary (state)","ofsted":"Outstanding","distance":"4.0 mi","url":"https://www.bohunt.hants.sch.uk/"}],"transport":{"nearestStation":"Liss (1.6 mi)","commutes":[{"to":"London Waterloo","time":"~1h 10m","mode":"drive to Liss + direct South Western Railway (Portsmouth Direct line)","source":"https://www.southwesternrailway.com/travelling-with-us/at-the-station/liss"},{"to":"Petersfield","time":"5m","mode":"South Western Railway (one stop)","source":"https://www.southwesternrailway.com/travelling-with-us/at-the-station/liss"}],"roads":"Immediately west of the A3 (London–Portsmouth) at the Liss/Stodham junction; B3006 north-west to Selborne and Alton"},"prices":{"avgSold12Mo":null,"avgDetached":null,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/gu33-6lh.html","asOf":"2026-05"},"thingsToDo":["Hangers Way and Shipwrights Way long-distance trails","Walking onto Stoner Hill and Wheatham Hill","Cycling on quiet lanes around Liss Forest","Liss Riverside walks (Caker Stream)"],"placesToEat":[{"name":"The Jolly Drover","type":"Pub and restaurant","notes":"Country pub on the London Road at West Liss","url":"https://thejollydrover.com/"},{"name":"The Spread Eagle","type":"Village pub","notes":"Pub in central Liss","url":"https://www.thespreadeagleliss.co.uk/"}],"pros":["Liss station within 2 miles for direct London Waterloo trains","Inside the South Downs National Park","Bohunt School at Liphook (4 mi) is a state secondary rated Outstanding","Courtyard format gives a small, manageable scheme rather than an isolated single property","A3 access immediately to the east for road journeys to London or Portsmouth"],"cons":["Functionally a courtyard of a handful of houses — no village identity, no shop, no pub on site","Adjacency to the A3 means some background road noise","Open-market turnover is essentially nil in most years (~3 sales in three years recorded at GU33 6LH)","Liss itself is a long linear village, not a market town — for a full town offer, Petersfield is the destination","Listed-building and SDNP planning constraints on most stock"],"whoItSuits":"Buyers seeking a specific high-spec barn conversion or modern courtyard property in a National Park setting, with main-line rail within two miles and A3 access on the doorstep. Likely a downsizer, country-second-home or rural-working-from-home household rather than a first-time buyer — sale prices recorded at the courtyard are in the £700k+ range. Not for buyers wanting a sociable village with pubs, shops and a school on foot.","nearestStation":"Liss (1.6 mi)","primarySupermarket":"Tesco Petersfield, Bedford Road (~3.5 mi); Waitrose Petersfield (~4 mi)","images":[],"sources":[{"label":"Wikipedia — Flexcombe","url":"https://en.wikipedia.org/wiki/Flexcombe"},{"label":"Streetcheck — Flexcombe Lane GU33 6LH","url":"https://www.streetcheck.co.uk/postcode/gu336lh"},{"label":"Check My Postcode — GU33 6LJ (Flexcombe Farm Cottages)","url":"https://checkmypostcode.uk/gu336lj"},{"label":"South Western Railway — Liss","url":"https://www.southwesternrailway.com/travelling-with-us/at-the-station/liss"},{"label":"Homes Estate Agents — Flexcombe Lane listing","url":"https://homesea.co.uk/property-for-sale/liss/flexcombe-lane-flexcombe-liss-hampshire-gu33-6lh/"},{"label":"East Hants DC — Council Tax 2026/27 (Liss parish)","url":"https://www.easthants.gov.uk/sites/default/files/2026-03/Council%20tax%20per%20valuation%20band%202026-27.pdf"}]},{"id":"ford-sp4","name":"Ford","village":"Ford","town":"Salisbury","county":"Wiltshire","postcode":"SP4","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.1652,"lng":-1.77744},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"four-marks-gu34","name":"Four Marks","village":"Four Marks","town":"Alton","county":"Hampshire","postcode":"GU34","hubCity":"Guildford","regionDir":"","settlementType":"","subRegion":"Alton","coords":{"lat":51.13612,"lng":-0.98344},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":"D","overview":"Four Marks is a village and civil parish of around 4,800 residents in the East Hampshire district, sitting astride the A31 road four and a half miles south-west of Alton on the high chalk ridge at 630 ft above sea level. The name records a Saxon-era boundary point where four parishes (Ropley, Medstead, Chawton and Farringdon) met; until the turnpike was driven through in 1753, the only settlement was the Windmill Inn and a few cottages. The parish was created in 1932 and has grown rapidly since the 1980s as developers acquired plots between the older hamlets of Hawthorn and Soldridge. The village shares Medstead and Four Marks railway station — at 644 ft, the highest standard-gauge station in southern England — with neighbouring Medstead, but the line is the preserved Watercress Line and does not run commuter services; commuters drive four miles to Alton for direct Waterloo trains. The St Swithun''s Way long-distance footpath crosses the southern fringe of the village.","character":"Recent-build commuter village layered over a Saxon boundary; the older cores at Hawthorn and Lymington Bottom retain a few period cottages but most of the modern parish is densely-packed late-20th and 21st-century estate housing, a marked contrast to neighbouring Medstead. Council Tax Band D charge for the parish in 2026/27 is £2,316.05 (East Hampshire local-authority data).","amenities":["Four Marks Co-op and small Tesco Express","Medstead and Four Marks station (Watercress Line, heritage only)","Triple fff Brewery taproom (Lymington Bottom Road)","Several cafés, hairdressers, wine merchant, florist, pharmacy","Two GP surgeries within parish","Four Marks Recreation Ground (football, cricket, tennis, bowls, BMX)","Four Marks Church of England Primary School","Church of the Good Shepherd","Hattingley Valley Wines (within parish, sparkling-wine producer)"],"schools":[{"name":"Four Marks Church of England Primary School","phase":"Primary","ofsted":null,"distance":"0.4 mi","url":"https://reports.ofsted.gov.uk/"},{"name":"Medstead Church of England Primary School","phase":"Primary","ofsted":"Good","distance":"1.8 mi","url":"https://reports.ofsted.gov.uk/provider/21/116300"},{"name":"Amery Hill School, Alton","phase":"Secondary","ofsted":null,"distance":"4.6 mi","url":"https://reports.ofsted.gov.uk/"},{"name":"Alton School (independent)","phase":"Through-school","ofsted":null,"distance":"4.5 mi","url":"https://reports.ofsted.gov.uk/"}],"transport":{"commutes":[{"to":"London Waterloo","time":"1h 13m","mode":"drive to Alton + direct train (South Western Railway)","source":"https://www.thetrainline.com/stations/alton"},{"to":"London Waterloo (fastest)","time":"1h 6m","mode":"drive + train","source":"https://www.thetrainline.com/train-times/alton-to-london-waterloo"},{"to":"Winchester (by road)","time":"~25m","mode":"drive (A31)","source":"https://www.nationalrail.co.uk/"}],"nearestStation":"Alton (4.4 mi)","roads":"A31 (through village); A32 ~4 mi; A3 ~10 mi; M3 J9 ~14 mi"},"prices":{"avgSold12Mo":534986,"avgDetached":null,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/gu34.html","asOf":"2026-05"},"thingsToDo":["Riding the Watercress Line (Alresford–Alton steam railway)","St Swithun''s Way walking (Winchester to Farnham)","Pilgrim''s Way long-distance path","Hattingley Valley Wines vineyard tours and tastings","Triple fff Brewery taproom evenings","Four Marks Recreation Ground (cricket, tennis, bowls, BMX)","Jane Austen''s House Museum, Chawton (3 mi)"],"placesToEat":[{"name":"Triple fff Brewery Taproom","type":"Brewery taproom","notes":"On-site brewery selling Moondance pale ale and Goldfinger lager; rustic bar","url":"https://triplefff.com/"},{"name":"Hattingley Valley Wines (cellar door)","type":"Vineyard tasting","notes":"English sparkling wine producer with tours and tastings","url":"https://hattingleyvalley.com/"},{"name":"Windmill Inn, Four Marks","type":"Village pub","notes":"On the original A31 turnpike site","url":"https://www.windmill-fourmarks.co.uk/"}],"pros":["Full village amenity set (shops, GP, schools, pubs, brewery, vineyard)","On the A31 corridor between Alton and Winchester","Direct Waterloo trains from Alton in just over an hour","Cheaper per-square-foot than Medstead or Chawton given housing mix"],"cons":["A31 traffic runs through the village and is often heavy","Late-20th-century estate density loses the chalk-village look","Watercress Line is heritage only — no commuter service from village station","Recent development has been controversial locally"],"whoItSuits":"Practical buyers prioritising amenities, schools and A31 access over picture-postcard character — particularly first-time buyers and growing families who would be priced out of Medstead, Bentworth or Beech. The mix of modern estate stock, two primaries within walking distance, a recreation ground with multiple sports and a small but real shopping parade makes it one of the more livable smaller villages in GU34. Less suitable for buyers chasing chalk-cottage aesthetics or planning to commute daily without a car: Alton station is a four-mile drive, and the Watercress Line is heritage, not transport.","broadbandMedianMbps":null,"nearestStation":"Alton (4.4 mi)","primarySupermarket":"Sainsbury''s, Draymans Way, Alton (4.5 mi); Co-op within village","images":[],"sources":["https://en.wikipedia.org/wiki/Four_Marks","https://watercressline.co.uk/visit/what-to-see/medstead-four-marks/","https://en.wikipedia.org/wiki/Medstead_and_Four_Marks_railway_station","https://www.easthants.gov.uk/sites/default/files/2026-03/Council%20tax%20per%20valuation%20band%202026-27.pdf","https://www.thetrainline.com/stations/alton","https://www.rightmove.co.uk/house-prices/gu34.html","https://parentview.ofsted.gov.uk/parent-view-results/survey/result/12039/17","https://littleplaceinthecountry.com/en/medstead-local-guide"]},{"id":"froxfield-green-gu32","name":"Froxfield Green","village":"","town":"Petersfield","county":"Hampshire","postcode":"GU32","hubCity":"","regionDir":"","settlementType":"","subRegion":"","coords":{"lat":51.0344,"lng":-0.9763},"coordsSource":"unset","houseTypeIds":[],"status":"researched","overview":"A village in the civil parish of Froxfield and Privett, East Hampshire district. Froxfield Green (formerly just ''Froxfield'' on Ordnance Survey maps until around 1960) sits on the high clay plateau north-west of Petersfield, about three miles from the market town and just north of the A272. The wider parish — which also contains High Cross, Privett and Bailey Green — had a population of 929 at the 2021 census. Around 825 feet above sea level, this is some of the highest ground in East Hampshire, with earthworks running north–south along the western edge of the village that may be Anglo-Saxon defensive works or a tribal boundary. Roman and Romano-British remains have been found south-east of the village. The original parish church at Froxfield Green was demolished in 1861; three of its Norman arches were reconstructed at the new St Peter''s at High Cross. The 1921 village war memorial remains the most prominent landmark at the centre of the village.","character":"Open-plateau settlement with widely spaced farmhouses and cottages, set among arable fields and the hangers to the east. Mostly working farms, period dwellings and converted outbuildings; a few newer infill houses. Inside the South Downs National Park, with strict landscape protection.","amenities":["Froxfield Green war memorial (1921)","(at High Cross ~1 mi:) Froxfield CofE Primary and Pre-School","King George V Memorial Village Hall (Froxfield)","St Peter''s Church, High Cross (1862, includes Norman arches from the demolished Froxfield Green church)","The Trooper Inn (High Cross, ~1.5 mi)","Footpath network across the parish and onto the Hangers Way"],"schools":[{"name":"Froxfield Church of England Primary and Pre-School","phase":"Primary (2–11)","ofsted":"Good (March 2024)","distance":"1.0 mi","url":"https://reports.ofsted.gov.uk/provider/21/116289"},{"name":"The Petersfield School","phase":"Secondary","ofsted":"Good","distance":"3.5 mi","url":"https://www.tps.hants.sch.uk/"},{"name":"Churcher''s College","phase":"Independent (3–18)","ofsted":null,"distance":"3.5 mi","url":"https://www.churcherscollege.com/"}],"transport":{"nearestStation":"Petersfield (3.0 mi)","commutes":[{"to":"London Waterloo","time":"1h 2m – 1h 17m direct","mode":"drive to Petersfield + direct South Western Railway","source":"https://www.southwesternrailway.com/train-times/petersfield-to-london-waterloo"},{"to":"Portsmouth Harbour","time":"~30m","mode":"Petersfield + direct South Western Railway","source":"https://www.southwesternrailway.com/travelling-with-us/at-the-station/petersfield"}],"roads":"A272 (Winchester–Midhurst) at the southern edge of the parish; A3 ~4 mi east at Petersfield"},"prices":{"avgSold12Mo":null,"avgDetached":null,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/gu32.html","asOf":"2026-05"},"thingsToDo":["Hangers Way walking","Ashford Hangers National Nature Reserve","Shoulder of Mutton Hill (Edward Thomas memorial)","Selborne and Gilbert White''s House (~4 mi)","Privett Holy Trinity church (Grade II* listed, Churches Conservation Trust)"],"placesToEat":[{"name":"The Trooper Inn","type":"Pub with rooms and restaurant","notes":"17th-century inn at High Cross with eight rooms and open-fire bar","url":"https://www.trooperinn.com/"},{"name":"The Pub With No Name (White Horse)","type":"Country pub with rooms","notes":"Unsigned 17th-century pub at Priors Dean, ~2.5 mi north-west","url":"https://www.thepubwithnoname.uk/"}],"pros":["Catchment Froxfield CofE Primary rated Good (March 2024) is just down the lane","Inside the South Downs National Park with deep landscape protection","Petersfield station within ~3 miles for direct London Waterloo trains","Genuine downland feel at over 800 feet above sea level — long views in every direction","Two heritage-quality pubs within easy walk or short drive (Trooper, Pub With No Name)"],"cons":["No shop, no pub, no active church within Froxfield Green itself — village amenities are at High Cross (~1 mi)","High elevation and clay plateau location — wind and winter cold are real factors","Stock is dominated by larger farmhouse and detached country properties; very limited starter / smaller-cottage supply","SDNP and parish settlement boundary tightly limit new build and extensions","Rural broadband varies sharply by postcode; some lanes still on slow ADSL"],"whoItSuits":"Buyers wanting a higher-elevation downland setting with the school, hall and pub at High Cross within walking range, and the Petersfield mainline within a short drive. Strong fit for families targeting Froxfield CofE Primary and the Petersfield/Churcher''s secondary route, and for country buyers attracted to the South Downs landscape. Less suited to first-time buyers — stock here is typically larger period or detached property, and the entry pricing reflects that.","nearestStation":"Petersfield (3.0 mi)","primarySupermarket":"Waitrose Petersfield, Lavant Street (~3.5 mi); Tesco Petersfield, Bedford Road (~4 mi)","images":[],"sources":[{"label":"Wikipedia — Froxfield Green","url":"https://en.wikipedia.org/wiki/Froxfield_Green"},{"label":"Wikipedia — Froxfield and Privett parish","url":"https://en.wikipedia.org/wiki/Froxfield_and_Privett"},{"label":"Froxfield Village Hall and Village Information","url":"https://www.froxfieldvillagehall.co.uk/village-information"},{"label":"Ofsted — Froxfield CofE Primary and Pre-School","url":"https://reports.ofsted.gov.uk/provider/21/116289"},{"label":"The Trooper Inn","url":"https://www.trooperinn.com/"},{"label":"South Western Railway — Petersfield to London Waterloo","url":"https://www.southwesternrailway.com/train-times/petersfield-to-london-waterloo"},{"label":"East Hants DC — Council Tax 2026/27 (Froxfield & Privett parish)","url":"https://www.easthants.gov.uk/sites/default/files/2026-03/Council%20tax%20per%20valuation%20band%202026-27.pdf"}]},{"id":"froxfield-green-gu34","name":"Froxfield Green","village":"Froxfield Green","town":"Petersfield","county":"Hampshire","postcode":"GU34","hubCity":"Guildford","regionDir":"","settlementType":"","subRegion":"Petersfield","coords":{"lat":51.15752,"lng":-0.99708},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"gomeldon-sp4","name":"Gomeldon","village":"Gomeldon","town":"Salisbury","county":"Wiltshire","postcode":"SP4","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.1888,"lng":-1.778},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"great-wishford-sp2","name":"Great Wishford","village":"Great Wishford","town":"Salisbury","county":"Wiltshire","postcode":"SP2","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.06176,"lng":-1.858},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"hambledon-po7","name":"Hambledon","village":"Hambledon","town":"Waterlooville","county":"Hampshire","postcode":"PO7","hubCity":"Portsmouth","regionDir":"North","settlementType":"Non-City","subRegion":"Waterlooville","coords":{"lat":50.86996,"lng":-1.03648},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"A village of ~1,000 residents in the Winchester district, set on chalk downland inside the South Downs National Park at the southern end of the Meon Valley. Famed as the \"cradle of cricket\" — the Hambledon Club at nearby Broadhalfpenny Down was central to the sport''s 18th-century development.","character":"Linear downland village, 69 listed buildings, Saxon-origin Grade I church; quietly affluent, history-conscious, families and downsizers.","amenities":["Two village shops","Pub (the Bat and Ball Inn at Broadhalfpenny Down acts as a cricket museum)","Parish church","Hambledon Primary (Ofsted Outstanding)","Active cricket club at Ridge Meadow"],"schools":[{"name":"Hambledon Primary School","phase":"Primary","type":"State","ofsted":"Outstanding (2024)","distance":"In village","url":"https://reports.ofsted.gov.uk/provider/21/116012"},{"name":"The Cowplain School","phase":"Secondary","type":"State","ofsted":"Good (2023)","distance":"~5 miles","url":"https://reports.ofsted.gov.uk/provider/23/136432"}],"transport":{"commutes":[{"to":"Portsmouth Harbour","mode":"Drive","typical":"~35–45 min","notes":"A32/A27 route dependent"},{"to":"Winchester","mode":"Drive","typical":"~30–35 min","notes":"A32 northbound"},{"to":"London Waterloo","mode":"Train (from Petersfield)","typical":"~1h + ~20 min drive to station","notes":"No station in Hambledon"}]},"prices":{"summary":"PO7 prices are generally lower than South Downs prime villages, but Hambledon tends to command a local premium.","average":"£390,218","detached":"£620,144","semiDetached":"£373,980","terraced":"£309,443","flat":"£183,522","asOf":"2026-04","sourceUrl":"https://www.rightmove.co.uk/house-prices/PO7.html"},"thingsToDo":["South Downs Way walking","Broadhalfpenny Down cricket heritage trail","Meon Valley cycling/walking"],"placesToEat":["The Bat and Ball Inn","The Vine at Hambledon"],"pros":["Outstanding primary school","Inside the National Park (planning protections)","Strong community + sporting fabric","Denmead nearby for full supermarket shop"],"cons":["No station — Petersfield or Rowlands Castle for trains","Tight planning regime limits extensions/alterations","Premium for SDNP postcodes"],"whoItSuits":["Families chasing the primary school and the National Park setting","Cricket-loving second-homers and retirees"],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[{"label":"Wikipedia — Hambledon, Hampshire","url":"https://en.wikipedia.org/wiki/Hambledon,_Hampshire"},{"label":"Hambledon Parish Council — Cricket Club","url":"https://www.hambledon-pc.gov.uk/Cricket/Cricket_Club.aspx"},{"label":"Visit South East England — Hambledon","url":"https://www.visitsoutheastengland.com/places-to-visit/hambledon-p1272711"},{"label":"Ofsted — Hambledon Primary School","url":"https://reports.ofsted.gov.uk/provider/21/116012"},{"label":"Ofsted — The Cowplain School","url":"https://reports.ofsted.gov.uk/provider/23/136432"},{"label":"Rightmove House Prices PO7","url":"https://www.rightmove.co.uk/house-prices/PO7.html"},{"label":"National Rail — Petersfield station","url":"https://www.nationalrail.co.uk/stations/petersfield/"}]}]'::jsonb) AS value;

